const items = $input.all();
const emailData = $('Email Trigger').first().json;
const results = [];

for (const item of items) {
  try {
    const content = item.json.content || '';
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      results.push({ json: { ...parsed, original_email: { from: emailData.from, subject: emailData.subject, date: emailData.date, text: emailData.text } } });
    } else {
      results.push({ json: { ist_geschaeftskunde: false, konfidenz: 0, firmenname: null, branche: null, begruendung: 'Kein JSON in GPT-Antwort gefunden', extrahierte_daten: {}, original_email: { from: emailData.from, subject: emailData.subject, date: emailData.date } } });
    }
  } catch (e) {
    results.push({ json: { ist_geschaeftskunde: false, konfidenz: 0, firmenname: null, branche: null, begruendung: 'Parse-Fehler: ' + e.message, extrahierte_daten: {}, original_email: { from: emailData.from, subject: emailData.subject, date: emailData.date } } });
  }
}

return results;

const items = $input.all();
const classData = $('Parse Klassifikation').first().json;
let authToken = null;
try { authToken = $('Creditsafe Auth').first().json.token; } catch(e) {}

const results = [];

for (const item of items) {
  const companies = item.json.companies || [];

  if (!authToken) {
    results.push({ json: { ...classData, creditsafe_error: true, creditsafe_error_msg: 'Authentifizierung fehlgeschlagen', company_id: null, company_found: false } });
  } else if (companies.length > 0) {
    results.push({ json: { ...classData, creditsafe_error: false, company_id: companies[0].id, company_name_cs: companies[0].name, company_found: true } });
  } else {
    results.push({ json: { ...classData, creditsafe_error: true, creditsafe_error_msg: 'Keine Firma bei Creditsafe gefunden', company_id: null, company_found: false } });
  }
}

return results;

