const items = $input.all();
const classData = $('Parse Klassifikation').first().json;
const extractData = $('Firma extrahieren').first().json;
let csReport = {};
try { csReport = $('Creditsafe Bericht').first().json; } catch(e) {}

const results = [];

for (const item of items) {
  try {
    const content = item.json.content || '';
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      results.push({ json: { firmenname: classData.firmenname, branche: classData.branche, extrahierte_daten: classData.extrahierte_daten, original_email: classData.original_email, company_id: extractData.company_id, company_found: extractData.company_found, creditsafe_error: extractData.creditsafe_error, ampel: parsed.ampel, score: parsed.score, ampel_begruendung: parsed.begruendung, risikofaktoren: parsed.risikofaktoren, empfehlung: parsed.empfehlung, creditsafe_raw: csReport } });
    } else {
      results.push({ json: { firmenname: classData.firmenname, branche: classData.branche, extrahierte_daten: classData.extrahierte_daten, original_email: classData.original_email, company_id: extractData.company_id, creditsafe_error: extractData.creditsafe_error, ampel: 'GELB', score: 0, ampel_begruendung: 'GPT-Antwort konnte nicht geparst werden', risikofaktoren: ['Parse-Fehler'], empfehlung: 'Manuelle Bonitätsprüfung durchführen' } });
    }
  } catch (e) {
    results.push({ json: { firmenname: classData.firmenname, branche: classData.branche, extrahierte_daten: classData.extrahierte_daten, original_email: classData.original_email, ampel: 'GELB', score: 0, ampel_begruendung: 'Fehler: ' + e.message, risikofaktoren: ['Verarbeitungsfehler'], empfehlung: 'Manuelle Bonitätsprüfung durchführen' } });
  }
}

return results;

const ampelData = $('Parse Ampel').first().json;

let apollo = {};
try { apollo = $('Apollo Enrichment').first().json; } catch(e) { apollo = { error: true, msg: 'Apollo nicht verfügbar: ' + e.message }; }

let linkedin = {};
try { linkedin = $('Apify LinkedIn').first().json; } catch(e) { linkedin = { error: true, msg: 'LinkedIn nicht verfügbar: ' + e.message }; }

let tavily = {};
try { tavily = $('Tavily Suche').first().json; } catch(e) { tavily = { error: true, msg: 'Tavily nicht verfügbar: ' + e.message }; }

let perplexity = {};
try { perplexity = $('Perplexity Analyse').first().json; } catch(e) { perplexity = { error: true, msg: 'Perplexity nicht verfügbar: ' + e.message }; }

const quellenVerfuegbar = [];
if (!apollo.error) quellenVerfuegbar.push('Apollo');
if (!linkedin.error) quellenVerfuegbar.push('LinkedIn');
if (!tavily.error) quellenVerfuegbar.push('Tavily');
if (!perplexity.error) quellenVerfuegbar.push('Perplexity');

return [{
  json: {
    firmenname: ampelData.firmenname,
    branche: ampelData.branche,
    extrahierte_daten: ampelData.extrahierte_daten,
    original_email: ampelData.original_email,
    ampel: ampelData.ampel,
    score: ampelData.score,
    ampel_begruendung: ampelData.ampel_begruendung,
    risikofaktoren: ampelData.risikofaktoren,
    empfehlung: ampelData.empfehlung,
    enrichment: { apollo: apollo, linkedin: linkedin, tavily: tavily, perplexity: perplexity },
    enrichment_datum: $now.toISO(),
    quellen_verfuegbar: quellenVerfuegbar
  }
}];

