const items = $input.all();
const enrichData = $('Merge Enrichment').first().json;
const results = [];

for (const item of items) {
  try {
    const content = item.json.content || '';
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    let summary = {};
    if (jsonMatch) { summary = JSON.parse(jsonMatch[0]); } else { summary = { zusammenfassung: content, parse_error: true }; }
    const kontakt = (summary.kontaktpersonen && summary.kontaktpersonen[0]) ? summary.kontaktpersonen[0] : {};
    const profil = summary.unternehmensprofil || {};
    const verkauf = summary.verkaufschancen || {};
    results.push({ json: { firmenname: enrichData.firmenname, branche: enrichData.branche, score: enrichData.score, ampel: enrichData.ampel, kontaktperson: kontakt.name || (enrichData.extrahierte_daten ? enrichData.extrahierte_daten.name : '') || '', position: kontakt.position || '', email: (enrichData.extrahierte_daten ? enrichData.extrahierte_daten.email : '') || kontakt.email || '', telefon: enrichData.extrahierte_daten ? (enrichData.extrahierte_daten.telefon || '') : '', website: profil.website || '', linkedin_url: profil.linkedin || '', groesse: profil.groesse || '', standort: profil.standort || '', zusammenfassung: summary.zusammenfassung || '', verkaufspotenzial: verkauf.potenzial || '', bedarfe: (verkauf.bedarfe || []).join(', '), pain_points: (verkauf.pain_points || []).join(', '), empfohlene_ansprache: summary.empfohlene_ansprache || '', aktuelle_news: (summary.aktuelle_news || []).join('; '), wettbewerber: (summary.wettbewerber || []).join(', '), quellen: enrichData.quellen_verfuegbar.join(', '), enrichment_datum: enrichData.enrichment_datum, enrichment: enrichData.enrichment, lead_summary: summary, original_email: enrichData.original_email, extrahierte_daten: enrichData.extrahierte_daten } });
  } catch (e) {
    results.push({ json: { firmenname: enrichData.firmenname, branche: enrichData.branche, score: enrichData.score, zusammenfassung: 'Parse-Fehler: ' + e.message, quellen: (enrichData.quellen_verfuegbar || []).join(', '), enrichment: enrichData.enrichment, original_email: enrichData.original_email, extrahierte_daten: enrichData.extrahierte_daten } });
  }
}

return results;
